const lead = $json.body || $json;
const fromEmail = process.env.CONTACT_FROM_EMAIL || 'NETA AI <hello@example.com>';
const ownerEmail = process.env.CONTACT_TO_EMAIL || 'neta.ai.pk@gmail.com';
const recommendedAutomation = lead.recommendedAutomation || 'Custom Business Workflow Automation';
const benefits = [
  'Reduce repetitive manual work',
  'Capture and qualify leads faster',
  'Notify your team automatically when a serious lead arrives'
];
const ownerHtml = `
  <h2>New NETA AI automation audit lead</h2>
  <p><strong>Name:</strong> ${lead.name || ''}</p>
  <p><strong>Business:</strong> ${lead.businessName || ''}</p>
  <p><strong>Email:</strong> ${lead.email || ''}</p>
  <p><strong>WhatsApp:</strong> ${lead.phone || ''}</p>
  <p><strong>Business Type:</strong> ${lead.businessType || ''}</p>
  <p><strong>Contact Channel:</strong> ${lead.contactChannel || ''}</p>
  <p><strong>Pain Point:</strong> ${lead.painPoint || ''}</p>
  <p><strong>Weekly Inquiries:</strong> ${lead.weeklyInquiries || ''}</p>
  <p><strong>Recommendation:</strong> ${recommendedAutomation}</p>
  <p><strong>Source:</strong> ${lead.source || 'NETA AI Website Automation Audit Assistant'}</p>
`;
const userHtml = `
  <div style="font-family: Arial, sans-serif; line-height: 1.6; max-width: 620px;">
    <h2>Your NETA AI automation audit request was received</h2>
    <p>Hi ${lead.name || 'there'},</p>
    <p>Thanks for completing the automation audit. Based on your answers, we recommend:</p>
    <div style="background:#f8fafc;border:1px solid #e2e8f0;border-radius:12px;padding:16px;margin:18px 0;">
      <strong>${recommendedAutomation}</strong>
    </div>
    <p>This can help you:</p>
    <ul>${benefits.map((benefit) => `<li>${benefit}</li>`).join('')}</ul>
    <p>NETA AI will contact you soon with the next steps.</p>
    <p>Best,<br />NETA AI</p>
  </div>
`;
return [{
  json: {
    lead,
    recommendedAutomation,
    benefits,
    ownerEmail,
    fromEmail,
    hasUserEmail: Boolean(lead.email),
    ownerPayload: {
      from: fromEmail,
      to: [ownerEmail],
      subject: `New automation audit lead - ${lead.name || 'Website visitor'}`,
      html: ownerHtml,
      reply_to: lead.email || undefined
    },
    userPayload: {
      from: fromEmail,
      to: lead.email ? [lead.email] : [],
      subject: 'Your NETA AI automation audit request was received',
      html: userHtml
    },
    responseBody: {
      success: true,
      recommendedAutomation,
      summary: `NETA AI received the audit request from ${lead.name || 'the visitor'} and recommended ${recommendedAutomation}.`,
      benefits,
      message: 'Your automation audit request has been received. NETA AI will contact you soon.'
    }
  }
}];
